"""Unit tests for BookCollection ADT."""import pytestfrom src.models.book import Bookfrom src.collections.book_collection import BookCollectionclass TestBookCollection:    """Test suite for BookCollection."""    @pytest.fixture    def empty_collection(self):        return BookCollection()    @pytest.fixture    def sample_book(self):        return Book("Test Book", "Author", "123", 2024)    def test_add_book_success(self, empty_collection, sample_book):        empty_collection.add_book(sample_book)        assert empty_collection.count() == 1        assert empty_collection.find_by_isbn("123") == sample_book    def test_add_duplicate_raises_error(self, empty_collection, sample_book):        empty_collection.add_book(sample_book)        with pytest.raises(ValueError, match="already exists"):            empty_collection.add_book(sample_book)    def test_remove_book_success(self, empty_collection, sample_book):        empty_collection.add_book(sample_book)        removed = empty_collection.remove_book("123")        assert removed == sample_book        assert empty_collection.count() == 0    def test_remove_checked_out_book_fails(self, empty_collection, sample_book):        sample_book.check_out()        empty_collection.add_book(sample_book)        with pytest.raises(ValueError, match="checked out"):            empty_collection.remove_book("123")